cat > /tmp/analyze_dlls.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;

var agentsAiDll = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net9.0/Microsoft.Agents.AI.dll");
var extensionsAiDll = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.extensions.ai/10.4.1/lib/net9.0/Microsoft.Extensions.AI.dll");

Console.WriteLine("=== MICROSOFT.AGENTS.AI TYPES ===\n");
var agentTypes = agentsAiDll.GetTypes()
    .Where(t => t.IsPublic && !t.IsNested)
    .OrderBy(t => t.Name);

foreach (var type in agentTypes)
{
    var kind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract class" : "class";
    Console.WriteLine($"[{kind}] {type.Name}");

    // Show public members for key types
    if (type.Name.Contains("Agent") || type.Name.Contains("Tool") || type.Name.Contains("Options") || type.Name.Contains("Worker") || type.Name.Contains("Message"))
    {
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName && m.DeclaringType == type)
            .Take(5);

        foreach (var method in methods)
        {
            Console.WriteLine($"  - {method.Name}");
        }

        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance)
            .Where(p => p.DeclaringType == type)
            .Take(5);

        foreach (var prop in props)
        {
            Console.WriteLine($"  - {prop.Name} (property)");
        }
    }
    Console.WriteLine();
}

Console.WriteLine("\n=== MICROSOFT.EXTENSIONS.AI KEY TYPES ===\n");
var extTypes = extensionsAiDll.GetTypes()
    .Where(t => t.IsPublic && !t.IsNested && 
           (t.Name.Contains("ChatMessage") || t.Name.Contains("ChatClient") || 
            t.Name.Contains("AIFunction") || t.Name.Contains("AITool") || 
            t.Name.Contains("AIContent")))
    .OrderBy(t => t.Name);

foreach (var type in extTypes)
{
    var kind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract class" : "class";
    Console.WriteLine($"[{kind}] {type.Name}");

    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance)
        .Where(m => !m.IsSpecialName && m.DeclaringType == type)
        .Take(3);

    foreach (var method in methods)
    {
        Console.WriteLine($"  - {method.Name}");
    }
    Console.WriteLine();
}
EOF
