// Quick exploration of the API surface
using System.Reflection;

var agentsPath = Directory.GetFiles(
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget", "packages", "microsoft.agents.ai"),
    "Microsoft.Agents.AI.dll", SearchOption.AllDirectories)
    .Where(p => p.Contains("net10") || p.Contains("net9") || p.Contains("net8") || p.Contains("netstandard"))
    .OrderByDescending(p => p)
    .FirstOrDefault();

if (agentsPath != null) {
    Console.WriteLine($"Found: {agentsPath}");
    var asm = Assembly.LoadFrom(agentsPath);
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName)) {
        Console.WriteLine($"\n=== {t.FullName} ===");
        if (t.BaseType != null && t.BaseType != typeof(object))
            Console.WriteLine($"  Extends: {t.BaseType.FullName}");
        foreach (var iface in t.GetInterfaces())
            Console.WriteLine($"  Implements: {iface}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  Method: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  Prop: {p.PropertyType.Name} {p.Name}");
        foreach (var c in t.GetConstructors())
            Console.WriteLine($"  Ctor: ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
} else {
    Console.WriteLine("DLL not found");
}
