var extensionsAssembly = Assembly.LoadFrom(extensionsPath);

Console.WriteLine("=== MICROSOFT.AGENTS.AI NAMESPACE ===\n");

var types = agentsAssembly.GetTypes()
    .Where(t => t.Namespace?.StartsWith("Microsoft.Agents.AI") == true && t.IsPublic && !t.IsNested)
    .OrderBy(t => t.Name);

foreach (var type in types)
{
    string kind = type.IsInterface ? "interface" : 
                  type.IsAbstract ? "abstract class" : 
                  type.IsEnum ? "enum" : "class";

    Console.WriteLine($"{kind} {type.Name}");

    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name)
        .Take(8);

    if (methods.Any())
    {
        Console.WriteLine("  Methods:");
        foreach (var m in methods)
        {
            var methodParams = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name));
            Console.WriteLine($"    - {m.Name}({methodParams}): {m.ReturnType.Name}");
        }
    }

    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .OrderBy(p => p.Name)
        .Take(6);

    if (props.Any())
    {
        Console.WriteLine("  Properties:");
        foreach (var p in props)
        {
            Console.WriteLine($"    - {p.Name}: {p.PropertyType.Name}");
        }
    }
    Console.WriteLine();
}

